"use strict";(self.webpackChunkwangdoc=self.webpackChunkwangdoc||[]).push([[8988],{4943:(e,t,n)=>{n.r(t),n.d(t,{data:()=>s});const s={key:"v-53a456d7",path:"/ssh-tutorial/sftp.html",title:"sftp 命令",lang:"zh-CN",frontmatter:{summary:"sftp 命令 sftp是 SSH 提供的一个客户端应用程序，主要用来安全地访问 FTP。因为 FTP 是不加密协议，很不安全，sftp就相当于将 FTP 放入了 SSH。 下面的命令连接 FTP 主机。 执行上面的命令，会要求输入 FTP 的密码。密码验证成功以后，就会出现 FTP 的提示符sftp> ，下面是一个例子。 FTP 的提示符下面，就可以输入各",head:[["meta",{property:"og:url",content:"https://yzqbooks.github.io/wangdoc/wangdoc/ssh-tutorial/sftp.html"}],["meta",{property:"og:site_name",content:"wangdoc"}],["meta",{property:"og:title",content:"sftp 命令"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-06T10:09:00.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-06T10:09:00.000Z"}]]},excerpt:"",headers:[],git:{createdTime:164923974e4,updatedTime:164923974e4,contributors:[{name:"yzqdev",email:"yzqdev@outlook.com",commits:1}]},readingTime:{minutes:.88,words:263},filePathRelative:"ssh-tutorial/sftp.md"}},18291:(e,t,n)=>{n.r(t),n.d(t,{default:()=>o});const s=(0,n(66252).uE)('<h1 id="sftp-命令" tabindex="-1"><a class="header-anchor" href="#sftp-命令" aria-hidden="true">#</a> sftp 命令</h1><p><code>sftp</code>是 SSH 提供的一个客户端应用程序，主要用来安全地访问 FTP。因为 FTP 是不加密协议，很不安全，<code>sftp</code>就相当于将 FTP 放入了 SSH。</p><p>下面的命令连接 FTP 主机。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ <span class="token function">sftp</span> username@hostname\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>执行上面的命令，会要求输入 FTP 的密码。密码验证成功以后，就会出现 FTP 的提示符<code>sftp&gt; </code>，下面是一个例子。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ <span class="token function">sftp</span> <span class="token environment constant">USER</span>@penguin.example.com\n<span class="token environment constant">USER</span>@penguin.example.com&#39;s password:\nConnected to penguin.example.com.\nsftp<span class="token operator">&gt;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>FTP 的提示符下面，就可以输入各种 FTP 命令了，这部分完全跟传统的 FTP 用法完全一样。</p><ul><li><code>ls [directory]</code>：列出一个远程目录的内容。如果没有指定目标目录，则默认列出当前目录。</li><li><code>cd directory</code>：从当前目录改到指定目录。</li><li><code>mkdir directory</code>：创建一个远程目录。</li><li><code>rmdir path</code>：删除一个远程目录。</li><li><code>put localfile [remotefile]</code>：本地文件传输到远程主机。</li><li><code>get remotefile [localfile]</code>：远程文件传输到本地。</li><li><code>help</code>：显示帮助信息。</li><li><code>bye</code>：退出 sftp。</li><li><code>quit</code>：退出 sftp。</li><li><code>exit</code>：退出 sftp。</li></ul>',8),a={},o=(0,n(83744).Z)(a,[["render",function(e,t){return s}]])},83744:(e,t)=>{t.Z=(e,t)=>{const n=e.__vccOpts||e;for(const[e,s]of t)n[e]=s;return n}}}]);